import React from 'react';

const DecorativeShapes = () => {
  return (
    <div className="decorative-shapes" style={{
      position: 'absolute',
      top: 0,
      left: 0,
      width: '100%',
      height: '100%',
      overflow: 'hidden',
      pointerEvents: 'none',
      zIndex: -1
    }}>
      {/* Top Left Blob */}
      <div style={{
        position: 'absolute',
        top: '-10%',
        left: '-5%',
        width: '40vw',
        height: '40vw',
        background: 'radial-gradient(circle, var(--primary-soft) 0%, transparent 70%)',
        opacity: 0.5,
        filter: 'blur(80px)',
        animation: 'float 20s infinite ease-in-out'
      }} />

      {/* Middle Right Blob */}
      <div style={{
        position: 'absolute',
        top: '25%',
        right: '-10%',
        width: '35vw',
        height: '35vw',
        background: 'radial-gradient(circle, var(--secondary-light) 0%, transparent 70%)',
        opacity: 0.4,
        filter: 'blur(100px)',
        animation: 'float-alt 25s infinite ease-in-out'
      }} />

      {/* Bottom Left Blob */}
      <div style={{
        position: 'absolute',
        bottom: '10%',
        left: '10%',
        width: '30vw',
        height: '30vw',
        background: 'radial-gradient(circle, var(--accent-light) 0%, transparent 70%)',
        opacity: 0.3,
        filter: 'blur(120px)',
        animation: 'float 22s infinite ease-in-out'
      }} />

      {/* Hero Section Accent */}
      <div style={{
        position: 'absolute',
        top: '60%',
        left: '50%',
        transform: 'translateX(-50%)',
        width: '50vw',
        height: '50vw',
        background: 'radial-gradient(circle, var(--primary-light) 0%, transparent 60%)',
        opacity: 0.2,
        filter: 'blur(150px)',
        animation: 'float-alt 30s infinite ease-in-out'
      }} />
    </div>
  );
};

export default DecorativeShapes;
